import { SetLabel, UpdateAnalogDomainValue, UpdateDigitalInPreset } from '../../types/context';
import { SignalAnalogDomainValueEnum } from '../../types/sources';
import { DigitalInPreset } from '../../types/sources';
import { MessageInvoker, UREventTarget } from '../message-invoker';
import { SOURCE_MESSAGE_TYPE_BASE } from './source.service';

/**
 *
 */
export class SignalService {
    /**
     *
     */
    constructor(
        private readonly eventTarget: Worker | UREventTarget,
        public sourceID: string,
    ) {}

    /** Update the label for a specific signal id
     * @param signalID id for the signal being labelled
     * @param label the new label for the signal
     * @deprecated Source contributions will be responsible for labels for signals directly
     */
    async updateSignalLabel(signalID: string, label: string): Promise<void> {
        const setLabel: SetLabel = {
            sourceID: this.sourceID,
            signalID,
            label,
        };
        return MessageInvoker.postAndAwait(this.eventTarget, SOURCE_MESSAGE_TYPE_BASE + 'updateSignalLabel', setLabel);
    }

    /** Update the Analog Domain for a specific signal id
     * @param signalID id for the signal being changed
     * @param analogDomainValueEnum the domain to set
     * @deprecated should be handled by the individual contribution
     */
    async updateSignalAnalogDomain(signalID: string, analogDomainValueEnum: SignalAnalogDomainValueEnum): Promise<void> {
        const updateAnalogDomainValue: UpdateAnalogDomainValue = {
            sourceID: this.sourceID,
            signalID,
            analogDomain: analogDomainValueEnum,
        };
        return MessageInvoker.postAndAwait(
            this.eventTarget,
            SOURCE_MESSAGE_TYPE_BASE + 'updateSourceSignalAnalogDomain',
            updateAnalogDomainValue,
        );
    }

    /**
     * Set the Preset Action for a given Digital-In signal
     * @param signalID ID of the signal to set the preset for
     * @param preset the preset to set
     * @deprecated Source contributions will be responsible for handling presets themselves
     */
    setDigitalInPreset(signalID: string, preset: DigitalInPreset): Promise<void> {
        const updateAnalogInPreset: UpdateDigitalInPreset = {
            sourceID: this.sourceID,
            signalID,
            preset,
        };
        return MessageInvoker.postAndAwait(this.eventTarget, SOURCE_MESSAGE_TYPE_BASE + 'setDigitalInPreset', updateAnalogInPreset);
    }
}
