import { MessageInvoker, UREventTarget } from '../message-invoker';

export const SYSTEM_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SystemService.';

/**
 * Service that handles system information.
 */
export class SystemService {
    worker: Worker | UREventTarget;

    /**
     * Create a service for the specific worker
     * @param worker
     */
    constructor(worker: Worker | UREventTarget) {
        this.worker = worker;
    }

    /**
     * Get the software version.
     * @returns The software version.
     */
    getSoftwareVersion(): Promise<string> {
        return MessageInvoker.postAndAwait(this.worker, SYSTEM_SERVICE_MESSAGE_TYPE_BASE + 'getSoftwareVersion');
    }
}
