import { SmartSkillInstance } from '../types/nodes';
import { MessageInvoker, UREventTarget } from './message-invoker';

export const SMART_SKILL_INSTANCE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SmartSkillInstanceService.';

/**
 * Service that handles updating smart skill instances
 */
export class SmartSkillInstanceService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(private readonly eventTarget: Worker | UREventTarget) {}

    /**
     * Update the program node
     * @param instance New smart skill instance data
     */
    async updateInstance(instance: SmartSkillInstance): Promise<void> {
        return MessageInvoker.postAndAwait(this.eventTarget, SMART_SKILL_INSTANCE_SERVICE_MESSAGE_TYPE_BASE + 'updateInstance', {
            instance,
        });
    }
}
