import { Guid } from 'guid-typescript';
import { Observable, Subject } from 'rxjs';
import { finalize } from 'rxjs/operators';
import { Md5 } from 'ts-md5';

export const UNSUBSCRIBE_MESSAGE_TYPE = 'ur.web.message.unsubscribeUpdates';

/**
 * Options for creating a UREventTarget
 * @param name For manually setting the name of the event target. Will take precedence if provided.
 * @param values String values that will be hashed to create the event target name.
 * @param salt Salt to add to the event target name. Will be appended.
 */
type UREventTargetOptions = {
    name?: string;
    values?: Array<string>;
    salt?: string;
};
/**
 *
 */
export class UREventTarget extends EventTarget {
    name?: string;
    /**
     *
     * @param name
     */
    constructor(options?: UREventTargetOptions) {
        super();
        this.name = options?.name || Md5.hashStr(`${options?.values?.join('')}${options?.salt}`);
    }
}

/**
 * returns a reply promise to the specified message
 *
 * @param eventTarget The worker or event target where to send the message
 * @param type The type of message being sent
 * @param data The message data
 */
export function postAndAwait<T>(eventTarget: Worker | UREventTarget, type: string, data: any = {}): Promise<T> {
    const id = Guid.raw();
    return new Promise((resolve, reject) => {
        let channel: MessageChannel | undefined;
        if (isWorker(eventTarget)) {
            channel = new MessageChannel();
            channel.port1.addEventListener('message', (event) => {
                channel?.port1.close();
                if (event.data.error) {
                    reject(event.data.error);
                } else {
                    resolve(event.data.data);
                }
            });
            channel.port1.start();
        } else {
            eventTarget.addEventListener(
                `reply_${type}_${id}`,
                (event: Event) => {
                    resolve((event as MessageEvent).data.data);
                },
                { once: true },
            );
        }
        const message: { type: string; data: unknown; id: string; name?: string } = {
            type,
            data,
            id,
        };
        const name = (eventTarget as UREventTarget)?.name || self.name;
        if (name) {
            message.name = name;
        }
        dispatchWorkerOrTargetEvent(eventTarget, message, channel);
    });
}

/**
 * returns an observable that will emit any messages replied to the specified message
 *
 * @param eventTarget The worker or event target where to send the message
 * @param type The type of message being sent
 * @param data The message data
 */
export function postAndObserve<T>(eventTarget: Worker | EventTarget, type: string, data: any): Observable<T> {
    const id = Guid.raw();
    const response$ = new Subject<T>();
    let channel: MessageChannel | undefined;
    let callback: EventListener;
    if (isWorker(eventTarget)) {
        /**
         * Handles data and sends it on to the worker through observable
         * @params the event containing data
         */
        callback = (e) => {
            const event = e as MessageEvent;
            channel?.port1.close();
            if (event.data.error) {
                response$.error(event.data.error);
            } else {
                response$.next(event.data.data);
            }
        };
        channel = new MessageChannel();
        channel.port1.addEventListener('message', callback, { passive: true });
        channel.port1.start();
    } else {
        /**
         * Handles data and sends it on to the EventTarget through observable
         * @params the event containing data
         */
        callback = (event) => {
            if (response$.observed) {
                response$.next((event as MessageEvent).data.data);
            }
        };

        eventTarget.addEventListener(`reply_${type}_${id}`, callback, {
            passive: true,
        });
    }
    const message = {
        type,
        data: {
            ...data,
        },
        id,
    };
    dispatchWorkerOrTargetEvent(eventTarget, message, channel);
    return response$.pipe(finalize(() => unsubscribeOnFinalized(eventTarget, type, id, callback, channel)));
}

/**
 * Sends an unsubscribe event to app for closing subscriptions and removes internal listeners
 * @param eventTarget the worker or event target where to send the message
 * @param type the type of message
 * @param id the id of the subscription
 * @param channel if sending to a worker a message channel must be provided
 * @param callback the callback to be called when unsubscribing
 */
function unsubscribeOnFinalized(
    eventTarget: Worker | EventTarget,
    type: string,
    id: string,
    callback: EventListener,
    channel?: MessageChannel,
) {
    if (isWorker(eventTarget)) {
        channel?.port1?.removeEventListener('message', callback);
    } else {
        eventTarget.removeEventListener(`reply_${type}_${id}`, callback);
    }
    const unsubscribeMessage = {
        type: UNSUBSCRIBE_MESSAGE_TYPE,
        data: { id },
    };
    dispatchWorkerOrTargetEvent(eventTarget, unsubscribeMessage, channel);
}

/**
 * send a message to the specified worker or target event
 * @param eventTarget the worker or event target where to send the message
 * @param message the message to be sent
 * @param channel if sending to a worker a message channel must be provided
 */
function dispatchWorkerOrTargetEvent(eventTarget: Worker | EventTarget, message: unknown, channel?: MessageChannel) {
    if (isWorker(eventTarget)) {
        if (!channel?.port2) {
            throw new Error('A channel must be provided when sending to a worker');
        }
        // TODO: Don't think this is a real fix, but it is a workaround for the issue
        if ((message as any)?.type === UNSUBSCRIBE_MESSAGE_TYPE) {
            eventTarget.postMessage(message);
        } else {
            eventTarget.postMessage(message, [channel.port2]);
        }
    } else {
        eventTarget.dispatchEvent(new MessageEvent('request', { data: message }));
    }
}

/**
 * returns true if the item is a worker type
 * @param item
 */
function isWorker(item: Worker | EventTarget): item is Worker {
    return (item as any).postMessage && typeof (item as any).postMessage === 'function';
}

/**
 * Abstract class for invoking messages
 */
export abstract class MessageInvoker {
    static readonly postAndAwait = postAndAwait;
    static readonly postAndObserve = postAndObserve;
}

/**
 * Base class for invoking messages
 */
export abstract class MessageInvokerService {
    /**
     * @constructor
     * @param messageBase
     * @param eventTarget
     */
    protected constructor(
        private readonly messageBase: string,
        readonly eventTarget: Worker | UREventTarget,
    ) {}

    /**
     * returns a reply promise to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    async postAndAwait<T>(type: string, data: any = {}): Promise<T> {
        return MessageInvoker.postAndAwait(this.eventTarget, this.messageBase + type, data);
    }

    /**
     * returns an observable that will emit any messages replied to the specified message
     *
     * @param type The type of message being sent
     * @param data The message data
     */
    postAndObserve<T>(type: string, data: any = {}): Observable<T> {
        return MessageInvoker.postAndObserve(this.eventTarget, this.messageBase + type, data);
    }
}
