import { CloseDialog, GenericDialogOptions } from '@universal-robots/ui-models';
import { MessageInvoker, UREventTarget } from '../message-invoker';

export const DIALOG_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.DialogService.';

/**
 * Service for open a dialog
 */
export class DialogService {
    worker;

    /**
     * Create a service for the specific worker
     * @param worker
     */
    constructor(worker: Worker | UREventTarget) {
        this.worker = worker;
    }

    /**
     * Open a Confirmation Dialog with a single dismiss button.
     * @param title Dialog title
     * @param text Dialog message
     * @param icon Dialog icon. It can be 'info', 'warning', 'error', or other icon strings.
     * @param confirmText Optional. Text for confirm button. Default to 'OK'.
     * @param  confirmIcon Optional. icon for confirm button. Default to no icon.
     */
    openConfirmDialog(title: string, text: string, icon: string, confirmText?: string, confirmIcon?: string): Promise<CloseDialog<never>> {
        return MessageInvoker.postAndAwait(this.worker, DIALOG_SERVICE_MESSAGE_TYPE_BASE + 'openConfirmDialog', {
            title,
            text,
            icon,
            textIsTranslationKey: false,
            confirmText,
            confirmIcon,
            replacementPatterns: undefined,
            replacements: undefined,
            showCancelButton: false,
            cancelText: undefined,
        });
    }

    /**
     * Open a Confirmation Dialog with a single dismiss button.
     * @param title Dialog title
     * @param text Dialog message
     * @param icon Dialog icon. It can be 'info', 'warning', 'error', or other icon strings.
     * @param confirmText Optional. Text for confirm button. Default to 'Confirm'.
     * @param confirmIcon Optional. Icon for confirm button. Default to no icon.
     * @param cancelText Optional. Text for cancel button. Default to 'Go Back'.
     */
    openConfirmCancelDialog(
        title: string,
        text: string,
        icon: string,
        confirmText?: string,
        confirmIcon?: string,
        cancelText?: string,
    ): Promise<CloseDialog<never>> {
        return MessageInvoker.postAndAwait(this.worker, DIALOG_SERVICE_MESSAGE_TYPE_BASE + 'openConfirmDialog', {
            title,
            text,
            icon,
            textIsTranslationKey: false,
            confirmText,
            confirmIcon,
            replacementPatterns: undefined,
            replacements: undefined,
            showCancelButton: true,
            cancelText,
        });
    }

    /**
     * Open a Custom Webcomponent Dialog
     * @param componentTag The tagname of the webcomponent to render in the dialog
     * @param initialData The initial data to be passed to the dialog component upon opening
     * @param options
     */
    openCustomDialog<ParamType = any, ReturnType = ParamType>(
        componentTag: string,
        initialData: ParamType,
        options?: GenericDialogOptions,
    ): Promise<CloseDialog<ReturnType>> {
        return MessageInvoker.postAndAwait(this.worker, DIALOG_SERVICE_MESSAGE_TYPE_BASE + 'openCustomDialog', {
            componentTag,
            inputData: initialData,
            options,
        });
    }
}
