import { ProgramCodeService, TreeBuilder, UREventTarget } from '../services';
import { RobotMoveService, SmartSkillInstanceService } from '../services';
import { FreedriveService } from '../services/robot/freedrive.service';
import { CommonBehaviorAPI, CommonPresenterAPI } from './common.api';

/**
 * Provides access to Smart Skills related API features in BehaviorWorkers
 */
export class SmartSkillsBehaviorAPI extends CommonBehaviorAPI {
    /** Creates a new instance of the SmartSkillsBehaviorAPI to allow communication with the
     * surrounding application from within a WebWorker
     *
     * @param target A worker, provided with 'self' when created inside a web worker
     */
    constructor(target: Worker | UREventTarget) {
        super(target);
        this.builder = new TreeBuilder(target);
        this.programCode = new ProgramCodeService(target);
    }
    builder: TreeBuilder;
    programCode: ProgramCodeService;
}

/**
 *
 */
export class SmartSkillsPresenterAPI extends CommonPresenterAPI {
    /**
     * Create a new instance of the SmartSkillsPresenterAPI to allow a Presenter to interact with the API and update itself
     */
    constructor(target: Worker | UREventTarget, name: string) {
        super(target);
        this.smartSkillInstanceService = new SmartSkillInstanceService(target);
        this.robotMoveService = new RobotMoveService(target);
        this.freedriveService = new FreedriveService(target);
    }
    smartSkillInstanceService: SmartSkillInstanceService;

    /**
     * API for working with robot moves, i.e. bringing up the move screen etc.
     */
    robotMoveService: RobotMoveService;

    freedriveService: FreedriveService;
}
