import { Observable } from 'rxjs';
import { Frame, Pose } from '../../types/nodes';
import { MessageInvokerService, UREventTarget } from '../message-invoker';

export const FRAMES_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.FrameService.';
/**
 * Create, Read, Update, Delete functionality for frames
 * Parameters are aligned with URScript functions, see URScript manual for more info.
 */
export class FramesService extends MessageInvokerService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(override readonly eventTarget: Worker | UREventTarget) {
        super(FRAMES_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Add a frame with the name 'name' initialized at the specified pose expressed in the refFrame coordinate frame.
     * This command only adds a frame to the world, it does not attach it to the ref_frame coordinate frame.
     * Use attach_frame() to attach the newly added frame to ref_frame if desired.
     * @see ScriptBuilder#addFrame
     */
    addFrame(name: string, pose: Pose, refFrame = 'base'): Promise<void> {
        return this.postAndAwait('addFrame', { name, pose, refFrame });
    }

    /**
     * Delete the frame named frame from the world model.
     * The "world", "base", and "tcp" frames cannot be deleted.
     * Any frames that are attached to the deleted frame will be attached to the "world" frame with new frame offsets set
     * such that the detached frame does not move in the world.
     * This command will fail if the frame does not exist.
     * @see ScriptBuilder#deleteFrame
     */
    deleteFrame(name: string): Promise<void> {
        return this.postAndAwait('deleteFrame', { name });
    }

    /**
     * Changes the placement of the coordinate frame named name to the new placement given by pose that is defined in the refFrame coordinate frame.
     * This will fail if name is “world”, "tcp", or if the frame does not exist. Note: to move the "tcp" frame, use the set_tcp() command instead.
     * If being used with the part positioner product, the ref_name argument can be the name of an external axis or axis group.
     * @see ScriptBuilder#moveFrame
     */
    moveFrame(name: string, pose: Pose, refFrame = 'base'): Promise<void> {
        return this.postAndAwait('moveFrame', { name, pose, refFrame });
    }

    /**
     * Changes the orientation of the coordinate frame named name to the new orientation.
     * This will fail if name is “world”, "tcp", or if the frame does not exist. Note: to reorient the "tcp" frame, use the set_tcp() command instead.
     * @see ScriptBuilder#setFrameOrientation
     */
    setFrameOrientation(name: string, orientation: [number, number, number]): Promise<void> {
        return this.postAndAwait('setFrameOrientation', { name, orientation });
    }

    /**
     * Attaches the child frame to the parent world model object. The relative transform between the parent and child will be set such that
     * the child does not move in the world when the attachment occurs.
     * The child cannot be "world", "tcp", or the same as parent.
     * This will fail if child or parent is not an existing frame, or this makes the attachments form a closed chain.
     * @see ScriptBuilder#attachFrame
     */
    attachFrame(child: string, parent: string): Promise<void> {
        return this.postAndAwait('attachFrame', { child, parent });
    }

    /**
     * Returns an observable of live frame data.
     */
    observeFrames(): Observable<Frame[]> {
        return this.postAndObserve('observeFrames');
    }
}
