import { ApplicationNode } from '../../types/nodes';
import { MessageInvoker, UREventTarget } from '../message-invoker';

export const APPLICATION_NODE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.ApplicationNodeService.';

/**
 * Service that handles updating application nodes
 */
export class ApplicationNodeService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(private readonly eventTarget: UREventTarget) {}

    /**
     * Update the program node
     * @param node New program node state
     */
    async updateNode(node: ApplicationNode): Promise<void> {
        return MessageInvoker.postAndAwait(this.eventTarget, APPLICATION_NODE_SERVICE_MESSAGE_TYPE_BASE + 'updateNode', node);
    }
}
