import { ProgramNode } from '../../types/nodes';
import { MessageInvoker, UREventTarget } from '../message-invoker';

export const PROGRAM_NODE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.ProgramNodeService.';

/**
 * Service that handles node insertion and removal og nodes
 */
export class ProgramNodeService {
    /**
     * @constructor
     * @param eventTarget
     * @param selectedNodeId
     */
    constructor(
        private readonly eventTarget: Worker | UREventTarget,
        private readonly selectedNodeId: string,
    ) {}

    /**
     * Update the program node
     * @param node New program node state
     */
    async updateNode(node: ProgramNode): Promise<void> {
        return MessageInvoker.postAndAwait(this.eventTarget, PROGRAM_NODE_SERVICE_MESSAGE_TYPE_BASE + 'updateParentNode', {
            node,
            id: this.selectedNodeId,
        });
    }
}
