import { MessageInvoker, UREventTarget } from '../message-invoker';

export const PROGRAM_CODE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.ProgramCodeService.';

/**
 * Service that handles code generation
 */
export class ProgramCodeService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(private readonly eventTarget: Worker | UREventTarget) {}

    /**
     *
     */
    async generateModulesScriptCode(): Promise<string> {
        return MessageInvoker.postAndAwait(this.eventTarget, PROGRAM_CODE_SERVICE_MESSAGE_TYPE_BASE + 'GENERATE_MODULES_SCRIPT_CODE', {});
    }

    /**
     *
     */
    async generateGlobalFunctionsScriptCode(): Promise<string> {
        return MessageInvoker.postAndAwait(this.eventTarget, PROGRAM_CODE_SERVICE_MESSAGE_TYPE_BASE + 'GENERATE_FUNCTIONS_SCRIPT_CODE', {});
    }

    /**
     *
     */
    async generateModulesAndGlobalFunctionsScriptCode(): Promise<string> {
        return MessageInvoker.postAndAwait(
            this.eventTarget,
            PROGRAM_CODE_SERVICE_MESSAGE_TYPE_BASE + 'GENERATE_MODULES_AND_FUNCTIONS_SCRIPT_CODE',
            {},
        );
    }

    /**
     *
     */
    async getProgramPreambleScriptCode(): Promise<string> {
        return MessageInvoker.postAndAwait(
            this.eventTarget,
            PROGRAM_CODE_SERVICE_MESSAGE_TYPE_BASE + 'GET_PROGRAM_PREAMBLE_SCRIPT_CODE',
            {},
        );
    }
}
