import { TreeBuilder, ProgramNodeService, RobotMoveService, UREventTarget, FramesService, MotionProfilesService } from '../services';
import { ValidationService } from '../services';
import { CommonBehaviorAPI, CommonPresenterAPI } from './common.api';

/**
 * Provides access to Program related API features in both BehaviorWorkers
 * and ProgramPresenters
 */
export class ProgramBehaviorAPI extends CommonBehaviorAPI {
    /** Creates a new instance of the ProgramBehaviorAPI to allow communication with the
     * surrounding application from within a WebWorker
     *
     * @param target A worker, provided with 'self' when created inside a web worker
     */
    constructor(target: Worker | UREventTarget) {
        super(target);
        this.builder = new TreeBuilder(target);
        this.framesService = new FramesService(target);
        this.motionProfilesService = new MotionProfilesService(target);
    }
    builder: TreeBuilder;
    framesService: FramesService;
    motionProfilesService: MotionProfilesService;
}

/**
 * ProgramPresenterAPI
 */
export class ProgramPresenterAPI extends CommonPresenterAPI {
    /** Creates a new instance of the ProgramPresenterAPI, to allow communication with the
     * surrounding application from within a WebComponent
     *
     * @param target An EventTarget, provided by PolyScope X
     * @param selectedNodeId the id of the currently selected program node
     */
    constructor(
        target: UREventTarget,
        public selectedNodeId: string,
    ) {
        super(target);
        this.programNodeService = new ProgramNodeService(target, selectedNodeId);
        this.robotMoveService = new RobotMoveService(target);
        this.validationService = new ValidationService(target, selectedNodeId);
        this.builder = new TreeBuilder(target);
        this.framesService = new FramesService(target);
        this.motionProfilesService = new MotionProfilesService(target);
    }
    builder: TreeBuilder;
    programNodeService: ProgramNodeService;
    robotMoveService: RobotMoveService;
    validationService: ValidationService;
    framesService: FramesService;
    motionProfilesService: MotionProfilesService;
}
