import { MessageInvoker, UREventTarget } from '../message-invoker';

export const SNACKBAR_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SnackbarService.';

/**
 * Service that handles showing snack notifications.
 */
export class SnackbarService {
    worker: Worker | UREventTarget;

    /**
     * Create a service for the specific worker
     * @param worker
     */
    constructor(worker: Worker | UREventTarget) {
        this.worker = worker;
    }

    /**
     * Open a snack notification.
     * @param message Snackbar message
     * @param type Optional. Type of notification (success, error, warning, info(default)).
     * @param title Optional. Snackbar title
     */
    showSnackbar(message: string, type?: string, title?: string): Promise<any> {
        return MessageInvoker.postAndAwait(this.worker, SNACKBAR_SERVICE_MESSAGE_TYPE_BASE + 'showSnackbar', {
            message,
            type,
            title,
        });
    }
}
