import { LogMessage } from '../../types/common';
import { MessageInvoker, UREventTarget } from '../message-invoker';

export const LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.LogMessageService.';

/**
 * Service for sending log messages
 */
export class LogMessageService {
    worker;

    /**
     * Create a service for the specific worker
     * @param worker
     */
    constructor(worker: Worker | UREventTarget) {
        this.worker = worker;
    }
    /**
     * Sends a log message.
     *
     * @param message The message to be logged
     */
    sendLogMessage(message: LogMessage): Promise<void> {
        return MessageInvoker.postAndAwait(this.worker, LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE + 'sendLogMessage', message);
    }

    /**
     * Sends a warning log message.
     *
     * @param message The message to be logged
     * @param type The type of message - if not specified 'generic' will be used
     */
    warn(message: string, type = 'generic'): Promise<void> {
        return MessageInvoker.postAndAwait(this.worker, LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE + 'warn', { message, type });
    }

    /**
     * Sends a info log message.
     *
     * @param message The message to be logged
     * @param type The type of message - if not specified 'generic' will be used
     */
    info(message: string, type = 'generic'): Promise<void> {
        return MessageInvoker.postAndAwait(this.worker, LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE + 'info', { message, type });
    }

    /**
     * Sends a debug log message.
     *
     * @param message The message to be logged
     * @param type The type of message - if not specified 'generic' will be used
     */
    debug(message: string, type = 'generic'): Promise<void> {
        return MessageInvoker.postAndAwait(this.worker, LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE + 'debug', { message, type });
    }

    /**
     * Sends a error log message.
     *
     * @param message The message to be logged
     * @param type The type of message - if not specified 'generic' will be used
     */
    error(message: string, type = 'generic'): Promise<void> {
        return MessageInvoker.postAndAwait(this.worker, LOG_MESSAGE_SERVICE_MESSAGE_TYPE_BASE + 'error', { message, type });
    }
}
