import { Observable } from 'rxjs';
import {
    FunctionsMap,
    GlobalVariable,
    URFunction,
    URLogicProgram,
    URModule,
    URSymbolType,
    URVariable,
    VariableValueType,
} from '../../types/nodes';
import { MessageInvoker, UREventTarget } from '../message-invoker';

export const SYMBOL_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.SymbolService.';

/**
 * Service for generating and getting reserved variable names
 */
export class SymbolService {
    worker;

    /**
     * Create a service for the specific worker
     * @param worker
     */
    constructor(worker: Worker | UREventTarget) {
        this.worker = worker;
    }
    /**
     * Get a list of available variables
     * @returns
     */
    getVariables(): Promise<Array<URVariable>> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getVariables', {});
    }
    /**
     * Get an observable of available variables
     */
    variables(): Observable<Array<URVariable>> {
        return MessageInvoker.postAndObserve(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'variables', {});
    }

    /**
     * Returns a list of the global variables as a stream.
     * @returns {Observable<Array<GlobalVariable>>} Observable of global variables object
     */
    globalVariables(): Observable<Array<GlobalVariable>> {
        return MessageInvoker.postAndObserve(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'globalVariables', {});
    }

    /**
     * Generates a new variable. The variable name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName The intended name for the variable, will be suffixed if the name is already taken
     * @param valueType The ValueType of the variable
     * @param blacklist Optional parameter to provide additional names which shouldn't be used.
     */
    generateVariable(suggestedName: string, valueType: VariableValueType, blacklist?: Array<string>): Promise<URVariable> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'generateVariable', {
            suggestedName,
            valueType,
            blacklist,
        });
    }

    /**
     * Return true if the provided name is the name of a registered variable
     *
     * @param variableName
     */
    isRegisteredVariableName(variableName: string): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isRegisteredVariableName', variableName);
    }
    /**
     * Get a list of available functions for the given module name. If no name provided, functions for the global scope
     * @param moduleName
     * @returns
     */
    getFunctions(moduleName = ''): Promise<URFunction[]> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getFunctions', { moduleName });
    }

    /**
     * Get functions map. Contains a list of functions for each module name. Note: Empty string is the global scope.
     * @returns
     */
    getFunctionsMap(): Promise<FunctionsMap> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getFunctionsMap', {});
    }
    /**
     * Generates a new function. The function name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     * @param moduleName
     */
    generateFunction(suggestedName: string, moduleName?: string): Promise<URFunction> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'generateFunction', {
            functionName: suggestedName,
            moduleName,
        });
    }

    /**
     * Return true if the provided name is the name of a registered function
     *
     * @param functionName
     * @param moduleName
     */
    isRegisteredFunctionName(functionName: string, moduleName?: string): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isRegisteredFunctionName', {
            functionName,
            moduleName,
        });
    }

    /**
     * Get a list of available modules
     * @returns
     */
    getModuleNames(): Promise<Array<string>> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getModuleNames', {});
    }

    /**
     * Generates a new module. The module name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     */
    generateModule(suggestedName: string): Promise<URModule> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'generateModule', suggestedName);
    }

    /**
     * Return true if the provided name is the name of a registered module
     *
     * @param moduleName
     */
    isRegisteredModuleName(moduleName: string): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isRegisteredModuleName', { moduleName });
    }

    /**
     * Get a list of available Logic Programs
     * @returns
     */
    getLogicProgramNames(): Promise<Array<string>> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getLogicProgramNames', {});
    }

    /**
     * Generates a new Logic Program. The program name is based on the suggested name.
     * If the suggested name is not usable a new, based on the suggestion, will be created
     *
     * @param suggestedName
     */
    generateLogicProgram(suggestedName: string): Promise<URLogicProgram> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'generateLogicProgram', suggestedName);
    }

    /**
     * Return true if the provided name is the name of a registered Logic Program
     *
     * @param logicProgramName
     */
    isRegisteredLogicProgramName(logicProgramName: string): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isRegisteredLogicProgramName', {
            logicProgramName,
        });
    }

    /**
     *  Return true if the provided name is a registered name of the given type.
     * @param name
     * @param type
     * @param moduleName
     * @param unique
     * @returns
     */
    isRegisteredName(name: string, type: URSymbolType, moduleName?: string, unique = false): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isRegisteredName', {
            name,
            type,
            moduleName,
            unique,
        });
    }

    /**
     * Return true if the declaring program node is suppressed
     * @param name The name of the symbol
     * @param moduleName The module of the symbol if defined
     * @return Boolean describing if the declaring node is suppressed
     */
    isSuppressed(name: string, moduleName?: string): Promise<boolean> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'isSuppressed', { name, moduleName });
    }

    /**
     * Get the URVariable with the given name
     * @return URVariable with the given name
     * @param name Name of the variable to get
     */
    getVariable(name: string): Promise<URVariable | undefined> {
        return MessageInvoker.postAndAwait(this.worker, SYMBOL_SERVICE_MESSAGE_TYPE_BASE + 'getVariable', { name });
    }

    /**
     *
     * @param variableName name of the variable being validated
     * @param acceptedTypes an optional array of valid type strings, e.g., float.
     * @returns true if the variable is registered not suppressed, and is of a valid value type
     */
    async isValidVariable(variableName: string, acceptedTypes?: string[]): Promise<boolean> {
        const isRegistered = await this.isRegisteredVariableName(variableName);
        const isSuppressed = await this.isSuppressed(variableName);
        const variable = await this.getVariable(variableName);
        let isOfValidValueType = true;
        if (acceptedTypes) {
            isOfValidValueType = acceptedTypes.some((acceptedType) => acceptedType === variable?.valueType);
        }
        return isRegistered && !isSuppressed && isOfValidValueType;
    }
}
