import { FramesService, MountingService, ProgramExecutionService, RobotMoveService, ToolService, UREventTarget } from '../services';
import { OperatorScreenService } from '../services/operator-screen/operator-screen.service';
import { CommonBehaviorAPI, CommonPresenterAPI } from './common.api';

/**
 * API for operator screen presenter components
 */
export class OperatorScreenPresenterAPI extends CommonPresenterAPI {
    robotMoveService: RobotMoveService;
    programExecutionService: ProgramExecutionService;
    toolService: ToolService;
    mountingService: MountingService;
    framesService: FramesService;
    operatorScreenService: OperatorScreenService;

    /** Creates a new instance of the OperatorScreenPresenterAPI, to allow communication with the
     * surrounding application from within a WebComponent
     *
     * @param target An EventTarget, provided by PolyScope X
     */
    constructor(target: UREventTarget) {
        super(target);
        this.robotMoveService = new RobotMoveService(target);
        this.programExecutionService = new ProgramExecutionService(target);
        this.toolService = new ToolService(target);
        this.mountingService = new MountingService(target);
        this.framesService = new FramesService(target);
        this.operatorScreenService = new OperatorScreenService(target);
    }
}

/**
 * Provides access to Operator Screen related API features in BehaviorWorkers
 */
export class OperatorScreenBehaviorAPI extends CommonBehaviorAPI {
    /** Creates a new instance of the OperatorScreenBehaviorAPI to allow communication with the
     * surrounding application from within a WebWorker
     *
     * @param target A worker, provided with 'self' when created inside a web worker
     */
    constructor(target: Worker | UREventTarget) {
        super(target);
    }
}
