import { Observable } from 'rxjs';
import { FrameName, JointPositions, KinematicInfo, Pose, Waypoint } from '../../types/nodes';
import { MessageInvokerService, UREventTarget } from '../message-invoker';

export const ROBOT_POSITION_SERVICE_MESSAGE_TYPE_BASE = 'ur.web.message.RobotPositionService.';

/**
 * RobotPositionService is used to obtain information on the current robot position
 */
export class RobotPositionService extends MessageInvokerService {
    /**
     * @constructor
     * @param eventTarget
     */
    constructor(override readonly eventTarget: Worker | UREventTarget) {
        super(ROBOT_POSITION_SERVICE_MESSAGE_TYPE_BASE, eventTarget);
    }

    /**
     * Gets the id of the currently selected frame id to perform moves relative to
     */
    async getRelativeToFrameId(): Promise<string> {
        return this.postAndAwait('getRelativeToFrameId');
    }

    /**
     * Gets the kinematic info
     */
    async getKinematicInfo(): Promise<KinematicInfo> {
        return this.postAndAwait('getKinematicInfo');
    }

    /**
     * Get the inverse kinematics for the given pose and qNear
     * @param pose The pose to calculate the inverse kinematics for
     * @param qNear The joint positions to start the search from
     */
    async getInverseKinematics(pose: Pose, qNear: JointPositions): Promise<JointPositions> {
        return this.postAndAwait('getInverseKinematics', {
            pose,
            qNear,
        });
    }

    /**
     * Get the current pose of the TCP relative to the given frame
     */
    getPoseRelativeToFrame(frame: FrameName): Observable<Pose> {
        return this.postAndObserve('getPoseRelativeToFrame', { frame });
    }

    /**
     * Get the current joint positions of the robot
     */
    getJointPositions(): Observable<JointPositions> {
        return this.postAndObserve('getJointPositions');
    }

    /**
     * Get current position of the robot
     */
    async getCurrentPosition(): Promise<Waypoint> {
        return this.postAndAwait('getCurrentPosition');
    }
}
